#include <iostream>
#include <string>
using namespace std;

int main()
{
    cout << "Merhaba, Playground!" << endl;

    string name = "Dunya";
    cout << "Merhaba, " << name << "!" << endl;

    int numbers[] = {5, 12, 8, 1, 9, 3};
    int size = sizeof(numbers) / sizeof(numbers[0]);

    int maxNum = numbers[0];
    int sum = 0;

    for (int i = 0; i < size; i++)
    {
        if (numbers[i] > maxNum)
        {
            maxNum = numbers[i];
        }
        sum += numbers[i];
    }

    cout << "En buyuk sayi: " << maxNum << endl;
    cout << "Toplam: " << sum << endl;

    return 0;
}
